insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'Find the HCF of 84 and 132.', '84 और 132 का HCF ज्ञात कीजिए।', 'Euclid method: repeatedly subtract/reduce common parts; HCF(84,132) = 12. Therefore, answer = 12.', 'HCF is the largest number that divides both given numbers exactly. Prime factorisation or Euclid''s algorithm both isolate this common divisor. Final answer is 12.', 'Euclid method से common divisor निकालें; HCF(84,132) = 12। अतः answer = 12।', 'HCF सबसे बड़ी संख्या है जो दोनों numbers को exactly divide करती है। Prime factorisation या Euclid method दोनों same common divisor देते हैं। Final answer 12 है।', 'EASY', array['number-system','lcm-hcf','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '924', '924', false, 'Computed LCM 924 instead of HCF. The question asks for the greatest common factor.', 'LCM 924 निकाल दिया। Question HCF यानी greatest common factor पूछता है।');
