insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'What is the remainder when 347 is divided by 9?', '347 को 9 से divide करने पर remainder क्या होगा?', '9 × 38 = 342. 347 - 342 = 5. Therefore, answer = 5.', 'Division means dividend = divisor × quotient + remainder, with remainder smaller than the divisor. Here the leftover is the required value. Final answer is 5.', '9 × 38 = 342। 347 - 342 = 5। अतः answer = 5।', 'Division में dividend = divisor × quotient + remainder होता है, और remainder divisor से छोटा होता है। यहाँ बचा हुआ हिस्सा answer है। Final answer 5 है।', 'MEDIUM', array['number-system','remainders','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
