insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'Find the unit digit of 7^42.', '7^42 का unit digit ज्ञात कीजिए।', 'Unit digits of powers of 7 repeat cyclically. Put exponent 42 into that cycle; the selected unit digit is 9. Therefore, answer = 9.', 'Only the last digit matters for a unit digit problem. Multiplying last digits repeatedly creates a short repeating cycle, so large powers reduce to a cycle position. Final answer is 9.', '7 की powers का unit digit cycle में repeat होता है। Exponent 42 को cycle में रखकर unit digit 9 मिलता है। अतः answer = 9।', 'Unit digit problem में सिर्फ last digit matter करता है। Last digits multiply करते हुए छोटा repeating cycle बनाते हैं। Final answer 9 है।', 'MEDIUM', array['number-system','unit-digit','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
