insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 15, 'The first part of a quantity is 420, and it is 7 times the second part. Find the second part.', 'किसी quantity का पहला भाग 420 है और यह दूसरे भाग का 7 गुना है। दूसरा भाग ज्ञात कीजिए।', 'Let the second part be x. First part = 7x = 420; so x = 420/7 = 60. Therefore, answer = 60.', 'When one quantity is described as a multiple of another, assign the smaller unknown as x and translate the sentence into an equation before choosing the asked part. Final answer is 60.', 'दूसरा भाग x मानें। पहला भाग = 7x = 420; इसलिए x = 420/7 = 60। अतः answer = 60।', 'जब एक quantity दूसरी की multiple हो, smaller unknown को x मानकर equation बनाते हैं और पूछा गया part निकालते हैं। Final answer 60 है।', 'HARD', array['number-system','ratio-basics','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
