insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, 'Simplify: 18 ÷ 6 + 4 × 7.', 'Simplify कीजिए: 18 ÷ 6 + 4 × 7.', 'First divide and multiply: 18÷6=3, 4×7=28. Add: 3+28=31. Therefore, answer = 31.', 'BODMAS fixes operation order. Division and multiplication are handled before addition, moving left-to-right among same-priority operations. Final answer is 31.', 'पहले divide और multiply: 18÷6=3, 4×7=28। Add करें: 3+28=31। अतः answer = 31।', 'BODMAS operation order तय करता है। Division और multiplication addition से पहले होते हैं। Final answer 31 है।', 'EASY', array['simplification','bodmas','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
