insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'Five persons A, B, C, D, E sit in a row facing north. D sits at the left end. A sits immediately right of D. B sits immediately right of A. C sits immediately right of B. E sits at the right end. Who sits in the middle?', 'पाँच व्यक्ति A, B, C, D, E north-facing row में बैठे हैं। D sits at the left end. A sits immediately right of D. B sits immediately right of A. C sits immediately right of B. E sits at the right end. Middle में कौन बैठा है?', 'Final order left-to-right is D-A-B-C-E; middle seat is B. Therefore, answer = B.', 'For row seating facing north, the reader''s left and the persons'' left are the same. Write the final order before answering position questions. Final answer is B.', 'Final order left-to-right is D-A-B-C-E; middle seat is B. अतः answer = B।', 'North-facing row में reader का left और persons का left same होता है। Position answer देने से पहले final order लिखें। Final answer B है।', 'HARD', array['seating-arrangement','linear-seating','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
