insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'A person walks 8 km North, then 6 km East, then 3 km South. What is the final displacement from the starting point?', 'एक व्यक्ति 8 km North, then 6 km East, then 3 km South चलता है। Starting point से final displacement क्या है?', 'Net east-west displacement = 6; net north-south displacement = 5. Combine them to get 11 km by path, North-East. Therefore, answer = 11 km by path, North-East.', 'Direction problems are coordinate problems. Opposite directions cancel; perpendicular components combine to give final displacement and direction. Final answer is 11 km by path, North-East.', 'Net east-west displacement = 6; net north-south displacement = 5। इन्हें combine करने पर 11 km by path, North-East मिलता है। अतः answer = 11 km by path, North-East।', 'Direction problems coordinate problems हैं। Opposite directions cancel होते हैं; perpendicular components final displacement देते हैं। Final answer 11 km by path, North-East है।', 'EASY', array['direction-sense','displacement','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
